def main():
  Path(__file__).parent.joinpath("compact_pages.json").write_text(
      json.dumps(PAGES, ensure_ascii=False, indent=2), encoding="utf-8"
  )
  for p in PAGES:
    pid = p["page_id"]
    url = f"https://app.notion.com/p/{pid}"
    text = (
        f'<page url="{url}">\n<properties>\n'
        f"{json.dumps(p['props'], ensure_ascii=False)}\n</properties>\n</page>"
    )
    out = {"title": p["title"], "url": url, "text": text}
    (RAW / f"{pid}.json").write_text(json.dumps(out, ensure_ascii=False, indent=2), encoding="utf-8")
  print(f"saved {len(PAGES)} pages to notion_raw")


if __name__ == "__main__":
  main()
